import * as React from 'react';
import Product from '../models/product';

interface ProductCardInterface {
    img: string,
    descripcion: string,
    precio: string,
    uni_medida: string,
    noParte: string,
    idProd: string,
    prodsSolicitar: Product[],
    setProdsSolicitar: React.Dispatch<React.SetStateAction<Product[]>>
}

function ProductCard(p: ProductCardInterface) {
    return (
        <div className="card box" style={{ width: 300 }}>
            <div className="card-image columns is-vcentered is-centered">
                <figure className="image is-128x128 column">
                    <img src={`https://javaclusters-95554-0.cloudclusters.net/imagesProd/${p.img}`} alt="Placeholder" />
                </figure>
            </div>
            <div className="card-content">
                <div className="content">
                    <h6 className="title is-6" style={{ height: 30 }}>
                        {p.descripcion}
                    </h6>
                    <div className="subtitle is-6">
                        ${p.precio} ({p.uni_medida})
                    </div>
                    <span className="tag is-info is-medium">
                        {p.noParte}
                    </span>
                </div>
            </div>
            <footer className="card-footer">
                {
                    !p.prodsSolicitar.some(e => e.id === p.idProd)
                        ? <a
                            href="#!"
                            className="card-footer-item"
                            onClick={() => p.setProdsSolicitar(prodsSolicitar => {
                                return [...prodsSolicitar, {
                                    id: p.idProd,
                                    codigo: p.noParte,
                                    cantidad: "1",
                                    precioU: p.precio,
                                    precioT: p.precio,
                                    numPedido: "0",
                                    folio: "0",
                                    comentarios: p.descripcion
                                }]
                            })}
                        >Agregar</a>
                        : <React.Fragment>
                            <a
                                href="#!"
                                className="card-footer-item" onClick={() => {
                                    const index = p.prodsSolicitar.findIndex(e => e.id === p.idProd);
                                    let cant = parseInt(p.prodsSolicitar[index]?.cantidad as string) - 1;
                                    if (cant < 1) {
                                        p.setProdsSolicitar(prodsSolicitar => prodsSolicitar.filter(f => f.id !== p.idProd))
                                    }
                                    else {
                                        p.setProdsSolicitar(prodsSolicitar => prodsSolicitar.map(f => {
                                            if (f.id === p.idProd) {
                                                return { ...f, cantidad: `${cant}`, precioT: `${cant * parseFloat(f.precioU)}` }
                                            }
                                            else {
                                                return f
                                            }
                                        }))
                                    }

                                }}>-</a>
                            <a href="#!" className="card-footer-item">{p.prodsSolicitar.find(e => e.id === p.idProd)?.cantidad}</a>
                            <a href="#!" className="card-footer-item" onClick={() => {
                                const index = p.prodsSolicitar.findIndex(e => e.id === p.idProd);
                                let cant = parseInt(p.prodsSolicitar[index]?.cantidad as string) + 1;
                                p.setProdsSolicitar(prodsSolicitar => prodsSolicitar.map(f => {
                                    if (f.id === p.idProd) {
                                        return { ...f, cantidad: `${cant}`, precioT: `${cant * parseInt(f.precioU)}` }
                                    }
                                    else {
                                        return f
                                    }
                                }))
                            }}>+</a>
                        </React.Fragment>
                }
            </footer>
        </div>
    );
}

export { ProductCard };
